// Simulating async operations (no real network in this environment)
async function fetchUserById(id: number): Promise<{ id: number; name: string; role: string }> {
  // In real code, this would be: await fetch(`/api/users/${id}`)
  const users = [
    { id: 1, name: "Alice", role: "admin" },
    { id: 2, name: "Bob",   role: "editor" },
    { id: 3, name: "Carol", role: "viewer" },
  ];
  const user = users.find(u => u.id === id);
  if (!user) throw new Error(`User ${id} not found`);
  return user;
}

async function displayUser(id: number): Promise<void> {
  const user = await fetchUserById(id);  // user is { id, name, role } — NOT a Promise
  console.log(`${user.name} (${user.role})`);
}

async function main() {
  await displayUser(1);
  await displayUser(2);
  await displayUser(3);
}

main();

async function getUser(id: number): Promise<string> {
  const names = ["Alice", "Bob", "Carol", "Dan"];
  return names[id - 1] ?? "Unknown";
}

async function getScore(userId: number): Promise<number> {
  const scores = [2850, 1920, 3100, 740];
  return scores[userId - 1] ?? 0;
}

async function getBadges(userId: number): Promise<string[]> {
  const allBadges = [["streak_7", "first_tutorial"], ["bookworm"], ["streak_30", "speedster", "all_done"], ["first_tutorial"]];
  return allBadges[userId - 1] ?? [];
}

async function getUserProfile(userId: number): Promise<void> {
  // All three run in parallel — not sequentially
  const [name, score, badges] = await Promise.all([
    getUser(userId),
    getScore(userId),
    getBadges(userId),
  ]);

  // TypeScript knows: name=string, score=number, badges=string[]
  console.log(`${name}: ${score} XP, badges: ${badges.join(", ") || "none"}`);
}

async function main() {
  await getUserProfile(1);
  await getUserProfile(3);
}

main();

async function loadMetric(name: string, shouldFail: boolean): Promise<number> {
  if (shouldFail) throw new Error(`${name} service unavailable`);
  const mockData: Record<string, number> = {
    users: 1247, revenue: 84320, conversions: 342, churn: 28
  };
  return mockData[name] ?? 0;
}

async function loadDashboard(): Promise<void> {
  const metrics = ["users", "revenue", "conversions", "churn"];
  const failures = new Set(["churn"]); // simulate one failing service

  const results = await Promise.allSettled(
    metrics.map(m => loadMetric(m, failures.has(m)))
  );

  for (let i = 0; i < results.length; i++) {
    const result = results[i];
    const name = metrics[i];

    if (result.status === "fulfilled") {
      console.log(`✅ ${name}: ${result.value}`);
    } else {
      console.log(`❌ ${name}: ${result.reason.message}`);
    }
  }
}

loadDashboard();
